    db.flush()
    write_audit_log(
        db,
        actor_id=admin.id,
        action="organization.create",
        entity_name="Organization",
        entity_id=entity.id,
        before=None,
        after=_to_dict(entity, ["id", "name", "code", "is_active"]),
    )
