        db.flush()
        write_audit_log(
            db,
            actor_id=admin.id,
            action="scope_grant.create",
            entity_name="ScopeGrant",
            entity_id=grant.id,
            before=None,
            after={"id": grant.id, "user_id": grant.user_id, "scope_type": grant.scope_type.value, "scope_id": grant.scope_id},
        )
        db.commit()

    return ScopeGrantOut(
        id=grant.id,
        user_id=grant.user_id,
